SELECT DATE(TO_TIMESTAMP("block_timestamp" / 1000000)) AS "date", TO_VARCHAR(SUM(CASE WHEN "input" LIKE '0x40c10f19%' THEN 1 WHEN "input" LIKE '0x42966c68%' THEN -1 ELSE 0 END * COALESCE(TRY_TO_NUMBER(SUBSTRING("input", CASE WHEN "input" LIKE '0x40c10f19%' THEN 75 WHEN "input" LIKE '0x42966c68%' THEN 11 ELSE 1 END, 64), 'XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX'), 0) / 1000000), '$999,999,999,999.99') AS "Δ Total Market Value" FROM "CRYPTO"."CRYPTO_ETHEREUM"."TRANSACTIONS" WHERE "to_address" = '0xa0b86991c6218b36c1d19d4a2e9eb0ce3606eb48' AND ("input" LIKE '0x40c10f19%' OR "input" LIKE '0x42966c68%') AND YEAR(TO_TIMESTAMP("block_timestamp" / 1000000)) = 2023 GROUP BY DATE(TO_TIMESTAMP("block_timestamp" / 1000000)) ORDER BY "date" DESC